	/*BOOL*//*C BOOL C*/ function  stockinfo_PoststocksymbolInsert()
	{
		/*create associated view of turtledata*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: on insert of a new symbol into stockinfo*/
		/*	Use Case What: create a view on the turtledata for this symbol*/
		/*	Use Case Why: allow easier analysis*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		//Tried creating this as a trigger but MYSQL doesn't allow a variable in the create view statement so can't build them dynamically.
		$this->querystring = "create view finance_views.turtledata_" . $this->data['stocksymbol'] . " as select * from turtledata where symbol='" . $this->data['stocksymbol'] . "'";
		$this->GenericQuery();
		
		
		$this->data['idstockinfo'] = $this->data['lastinsertid'];
		        require_once( '../scripts/getbondratearray.php' );
		        $bondratearray = getbondratearray( "10" );
		        require_once( 'stockexchange.class.php' );
		 $exchange = new stockexchange();
		        $exchange->where = "idstockexchange = '" . $this->data['stockexchange'] . "'";
		        $exchange->Select();
		        $this->data['googlesymbol'] = $exchange->resultarray[0]['googlesymbol'];
		        require_once( '../scripts/financialstatements/getstockfinancials.php' );
		        //data has to contain stocksymbol, googlesymbol and idstockinfo
		        getstockfinancial( $this->data, $bondratearray );
		        return;
		        //!#136
		
		//If we don't have a return in the body in codemeta, return
		return TRUE;;
	}
